draft = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.draft) or {}
cell = BlueRidge.Common.Util.extractQualifiedValues(self.session.custom.cell) or {}
partValue = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.partItemId)

# Resolve part: a numeric option value is a real Item.Id; a typed (custom)
# value from allowCustomOptions arrives as a raw part-number string ->
# resolve to an itemId via Item.getByPartNumber.
itemId = None
if partValue is not None and partValue != "":
	try:
		itemId = int(partValue)
	except (ValueError, TypeError):
		row = BlueRidge.Parts.Item.getByPartNumber(partValue)
		if row is None:
			BlueRidge.Common.Notify.toast("Unknown part", "No active item matches '%s'." % partValue, "error")
			return
		itemId = row.get("Id")
if itemId is None:
	BlueRidge.Common.Notify.toast("Part required", "Scan or pick a part number.", "warning")
	return

# Piece count: text-field + proc coercion (proc takes an int).
pieceCount = None
pc = draft.get("pieceCount")
if pc is not None and ("%s" % pc).strip() != "":
	try:
		pieceCount = int(("%s" % pc).strip())
	except (ValueError, TypeError):
		BlueRidge.Common.Notify.toast("Invalid piece count", "Enter a whole number.", "warning")
		return

# Optional serial range -> int or None.
def _toIntOrNone(v):
	if v is None:
		return None
	s = ("%s" % v).strip()
	if s == "":
		return None
	try:
		return int(s)
	except (ValueError, TypeError):
		return None
minSerial = _toIntOrNone(draft.get("minSerialNumber"))
maxSerial = _toIntOrNone(draft.get("maxSerialNumber"))

vendorLot = draft.get("vendorLotNumber") or None

appUserId = self.session.custom.appUserId
termId = None
try:
	termId = self.session.custom.terminal.terminalLocationId
except:
	termId = None

data = {
	"itemId": itemId,
	"lotOriginTypeId": self.view.custom.receivedOriginId,
	"currentLocationId": cell.get("locationId"),
	"pieceCount": pieceCount,
	"vendorLotNumber": vendorLot,
	"minSerialNumber": minSerial,
	"maxSerialNumber": maxSerial,
}
res = BlueRidge.Lots.Lot.create(data, appUserId, termId)
BlueRidge.Common.Ui.notifyResult(res, successTitle="LOT created")
if not (res and res.get("Status")):
	return
newId = res.get("NewId")

# Print the LTT. TODO(phase4): no resolver exists yet for the Primary label
# type id or the Initial print-reason id (LotLabel has no getByCode helper and
# the view must not call system.db / invent SQL). Passing None best-effort; the
# proc/print may reject -> the UI holds on printFailed and offers Reprint.
pr = BlueRidge.Lots.LotLabel.printLabel({"lotId": newId, "labelTypeCodeId": None, "printReasonCodeId": None}, appUserId, termId)
BlueRidge.Common.Ui.notifyResult(pr, successTitle="LTT printed")
if not (pr and pr.get("Status")):
	self.view.custom.printFailed = True
	self.view.custom.lastLabelLotId = newId
else:
	self.view.custom.printFailed = False
	self.view.custom.lastLabelLotId = newId
	self.resetForm()
	system.perspective.navigate("/shop-floor/lot-detail/" + str(newId))

# Dedicated terminal: derive the working cell from the terminal's zone (parent),
# mirroring the Die Cast / Assembly dedicated bodies (receiving deposits at its zone).
t = self.session.custom.terminal
if t and t.get("zoneLocationId"):
	self.session.custom.cell = {"locationId": t.get("zoneLocationId"), "code": t.get("zoneName") or "", "name": t.get("zoneName") or ""}
# Operator gate: no logged-in operator -> open the initials popup OVER this screen.
# Non-blocking: the page populates behind the modal; session.custom is reactive.
if not self.session.custom.appUserId:
	system.perspective.openPopup("mpp-initials", "BlueRidge/Components/Popups/InitialsEntry", params={"popupId": "mpp-initials"}, modal=True, showCloseIcon=False, overlayDismiss=False)

